INSERT INTO learning_resource (title, author, publish_date, duration, type, level, category, description, image, views, rating, content) VALUES
('习近平总书记关于主题教育的重要讲话精神解读', '中央党校马克思主义学院', '2025-12-15', '2.5小时', 'video', '中级', 'video', '深入解读习近平总书记关于学习贯彻习近平新时代中国特色社会主义思想主题教育的重要讲话精神', 'https://picsum.photos/id/70/300/200', 4560, 4.9, '<h2>课程简介</h2><p>本课程围绕习近平总书记关于主题教育的重要讲话精神进行深入解读。</p>'),
